using Microsoft.EntityFrameworkCore;

// EF Core 9 Cosmos breaking changes addressed here:
//
// 1. Discriminator property renamed: EF Core 9 now uses "$type" instead of
//    "Discriminator". For existing documents that already store "Discriminator",
//    we must explicitly configure the old property name.
//
// 2. Synchronous I/O removed: Sync methods (ToList, First, SaveChanges, etc.)
//    now throw InvalidOperationException on the Cosmos provider.
//    All queries/saves must use async equivalents (ToListAsync, FirstAsync,
//    SaveChangesAsync, etc.).

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ShopDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Fix breaking change #1: Preserve existing "Discriminator" property
            // name so EF Core 9 can read documents written by EF Core 8.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

// Example showing the sync → async migration (breaking change #2).
class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // BEFORE (EF Core 8 — now throws in EF Core 9):
    //   var products = _db.Products.ToList();
    //   _db.SaveChanges();

    // AFTER (EF Core 9 — async required for Cosmos provider):
    public async Task<List<Product>> GetAllAsync()
        => await _db.Products.ToListAsync();

    public async Task AddAsync(Product product)
    {
        _db.Products.Add(product);
        await _db.SaveChangesAsync();
    }
}

